Since I am a text-based AI, I cannot directly generate a binary 3D file (like an `.obj` or `.fbx`) that you can download. However, I can provide you with **complete, runnable code** to render a 3D house using **Three.js** (a popular JavaScript library for 3D graphics in the browser).

You can copy the code below, save it as an `.html` file (e.g., `house.html`), and open it in any modern web browser to see the 3D model.

### Option 1: Interactive 3D House (Web Browser)
This code creates a procedural house with a roof, walls, a door, and a window. It includes lighting, shadows, and orbit controls so you can rotate around the house.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click & Drag to Rotate | Scroll to Zoom</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 15);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Building the House
        const houseGroup = new THREE.Group();

        // Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xE0E0E0 }); // White walls
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x4a3c31 }); // Dark wood
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 });

        // --- Floor ---
        const floorGeo = new THREE.BoxGeometry(20, 1, 20);
        const floorMat = new THREE.MeshStandardMaterial({ color: 0x555555 });
        const floor = new THREE.Mesh(floorGeo, floorMat);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // --- Main Body ---
        const bodyGeo = new THREE.BoxGeometry(10, 6, 8);
        const body = new THREE.Mesh(bodyGeo, wallMaterial);
        body.position.y = 3;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // --- Roof ---
        const roofGeo = new THREE.ConeGeometry(9, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 8;
        roof.rotation.y = Math.PI / 4; // Rotate to align with house
        roof.castShadow = true;
        houseGroup.add(roof);

        // --- Door ---
        const doorGeo = new THREE.BoxGeometry(2, 4, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 2, 4); // Front center
        door.castShadow = true;
        houseGroup.add(door);

        // --- Window ---
        const winGeo = new THREE.BoxGeometry(2, 2, 0.1);
        const win = new THREE.Mesh(winGeo, windowMaterial);
        win.position.set(0, 5, -3.9); // Back wall
        houseGroup.add(win);

        // --- Chimney ---
        const chimGeo = new THREE.BoxGeometry(1, 3, 1);
        const chim = new THREE.Mesh(chimGeo, wallMaterial);
        chim.position.set(4, 9, 0);
        chim.castShadow = true;
        houseGroup.add(chim);

        scene.add(houseGroup);

        // 5. Trees (Simple decoration)
        function createTree(x, z) {
            const treeGroup = new THREE.Group();

            // Trunk
            const trunkGeo = new THREE.CylinderGeometry(0.5, 0.5, 2);
            const trunkMat = new THREE.MeshStandardMaterial({ color: 0x8B4513 });
            const trunk = new THREE.Mesh(trunkGeo, trunkMat);
            trunk.position.y = 1;
            trunk.castShadow = true;

            // Leaves
            const leavesGeo = new THREE.ConeGeometry(2, 4, 8);
            const leavesMat = new THREE.MeshStandardMaterial({ color: 0x228B22 });
            const leaves = new THREE.Mesh(leavesGeo, leavesMat);
            leaves.position.y = 3;
            leaves.castShadow = true;

            treeGroup.add(trunk, leaves);
            treeGroup.position.set(x, 0, z);
            scene.add(treeGroup);
        }

        createTree(-8, -8);
        createTree(8, -5);
        createTree(-5, 8);

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  Copy the code block above.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in Chrome, Firefox, Safari, or Edge.

